-- Name: health_mv; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.health_mv AS
 SELECT date_trunc('hour'::text, ts) AS date_hour,
    service,
    (count(*))::integer AS check_count,
    (count(*) FILTER (WHERE (ok = true)))::integer AS ok_count,
    (count(*) FILTER (WHERE (ok = false)))::integer AS fail_count,
    trunc((((count(*) FILTER (WHERE (ok = true)))::numeric / (NULLIF(count(*), 0))::numeric) * 100.0), 2) AS uptime_percent,
    trunc((avg(latency_ms))::numeric, 2) AS avg_latency_ms,
    trunc((min(latency_ms))::numeric, 2) AS min_latency_ms,
    trunc((max(latency_ms))::numeric, 2) AS max_latency_ms,
    (array_agg(ok ORDER BY ts DESC))[1] AS latest_ok,
    (array_agg(error ORDER BY ts DESC))[1] AS latest_error
   FROM public.health_entry h
  WHERE (service = ANY (ARRAY['websocket'::text, 'redis'::text, 'tus'::text, 'database'::text, 'keycloak'::text]))
  GROUP BY (date_trunc('hour'::text, ts)), service
  WITH NO DATA;


